    if (log) {
        connect(this, &DigestionReverseEngineeringSystem::fileScanned, 
                [log](const QString &path, int stubs, const QString &lang) {
            log->append(QString("<span style='color:gray'>[%1]</span> <b>%2</b> - %3 stubs (%4)")
                       .arg(QTime::currentTime().toString())
                       .arg(path)
                       .arg(stubs)
                       .arg(lang));
